params.param:
[
            {name: "Layer Structure Verifier", type: "architecture-check", paths: ["src/"], commands: ["vendor/bin/deptrac analyse", "vendor/bin/deptrac analyse --formatter=json"], pass: "Exit 0, zero violations — all 4 DDD layers (Domain, Application, Infrastructure, Share) respect dependency rules", fail: "Any layer violation detected — dependency flows upward or crosses BC boundary"},
            {name: "Cross-BC Boundary Checker", type: "architecture-check", paths: ["src/"], commands: ["vendor/bin/deptrac analyse --filter=cross-bc", "per-BC grep for cross-BC use-imports inside each Domain layer, excluding Share and the same BC namespace"], pass: "Zero cross-BC imports in Domain/Application layers; only ACL adapters in Infrastructure cross BC boundaries", fail: "Direct cross-BC import found outside ACL adapter"}
          ]

[
              {name: "Full Suite Runner", type: "test-execution", paths: ["tests/"], commands: ["npx playwright test"], pass: "Exit 0, all E2E tests green when run as a single suite — no failures from shared state or missing fixtures", fail: "Any test failure when run together that passed in isolation — check test-results/ for traces and screenshots"},
              {name: "Isolation Checker", type: "test-execution", paths: ["tests/"], commands: ["npx playwright test --shard=random"], pass: "Exit 0, all tests pass in randomized order — no order-dependent failures", fail: "Test failure in randomized order indicates shared mutable state between tests — check test-results/ for traces and screenshots"}
            ]

[
            {name: "Static Analysis Verifier", type: "quality-gate", paths: ["src/"], commands: ["vendor/bin/phpstan analyse src/ --level=9", "vendor/bin/ecs check src/"], pass: "Both exit 0 — zero PHPStan errors at level 9, zero ECS violations", fail: "Any static analysis error or coding standard violation"},
            {name: "Test Suite Runner", type: "test-execution", paths: ["tests/"], commands: ["vendor/bin/phpunit --testsuite=unit", "vendor/bin/phpunit --testsuite=integration", "vendor/bin/phpunit --coverage-text"], pass: "All suites green, coverage meets threshold (default 80%)", fail: "Test failure or coverage below threshold"},
            {name: "Runtime Health Checker", type: "environment-check", paths: ["src/"], commands: ["bin/console", "bin/console doctrine:schema:validate", "bin/console doctrine:migrations:status", "grep for TODO/FIXME/HACK comments in src/ (expect zero)"], pass: "Console boots, schema valid, no pending migrations, zero TODO/FIXME/HACK", fail: "Boot failure, schema mismatch, pending migrations, or stale comments found"}
          ]
